from pathlib import Path


def validate_requirements_file(filepath: str) -> bool:
    """Validate that the requirements file exists and has expected format."""
    path = Path(filepath)

    if not path.exists():
        print(f"ERROR: Requirements file not found: {filepath}", file=sys.stderr)
        return False

    if not path.is_file():
        print(f"ERROR: Path is not a file: {filepath}", file=sys.stderr)
        return False

    # Resolve to absolute path and ensure no directory traversal
    resolved = path.resolve()
    allowed_dir = Path.cwd().resolve()
    try:
        resolved.relative_to(allowed_dir)
    except ValueError:
        print(
            f"ERROR: Requirements file must be within project directory: {filepath}",
            file=sys.stderr,
        )
        return False

    # Check file is not suspiciously large (> 1MB)
    if resolved.stat().st_size > 1_000_000:
        print(f"ERROR: Requirements file suspiciously large: {filepath}", file=sys.stderr)
        return False

    return True


def validate_requirements_content(filepath: str) -> bool:
    """
    Validate requirements file content for security issues.
    Checks for:
    - Pinned versions (no unpinned dependencies)
    - No suspicious URLs or custom index servers
    - Hash specifications present for supply chain security
    """
    dangerous_patterns = [
        re.compile(r"^--index-url\s", re.IGNORECASE),
        re.compile(r"^--extra-index-url\s", re.IGNORECASE),
        re.compile(r"^--find-links\s", re.IGNORECASE),
        re.compile(r"^--trusted-host\s", re.IGNORECASE),
        re.compile(r"^-f\s", re.IGNORECASE),
        re.compile(r"^-i\s", re.IGNORECASE),
    ]

    # Pattern for valid requirement lines: package==version or package==version --hash=algo:value
    valid_requirement = re.compile(
        r"^[a-zA-Z0-9][a-zA-Z0-9._-]*(\[[a-zA-Z0-9,._-]+\])?\s*==\s*[0-9][a-zA-Z0-9._*+-]*"
    )
    comment_or_empty = re.compile(r"^\s*(#.*)?$")
    option_line = re.compile(r"^--")

    has_hashes = False
    has_unpinned = False
    warnings = []

    with open(filepath, "r", encoding="utf-8") as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()

            # Skip empty lines and comments
            if comment_or_empty.match(line):
                continue

            # Check for dangerous pip options embedded in requirements
            for pattern in dangerous_patterns:
                if pattern.match(line):
                    print(
                        f"ERROR: Dangerous option found on line {line_num}: {line}",
                        file=sys.stderr,
                    )
                    print(
                        "Custom index URLs and trusted hosts are not allowed in requirements files.",
                        file=sys.stderr,
                    )
                    return False

            # Allow --hash and --require-hashes options
            if option_line.match(line):
                if line.startswith("--require-hashes"):
                    has_hashes = True
                    continue
                elif line.startswith("--hash="):
                    continue
                else:
                    print(
                        f"ERROR: Unsupported option on line {line_num}: {line}",
                        file=sys.stderr,
                    )
                    return False

            # Handle continuation lines (hashes after \)
            if line.startswith("--hash=") or line.startswith("\\"):
                continue

            # Validate requirement format - must be pinned with ==
            if not valid_requirement.match(line.split("\\")[0].split("--hash")[0].strip()):
                # Check if it's a requirement without pinning
                if re.match(r"^[a-zA-Z0-9][a-zA-Z0-9._-]*", line):
                    has_unpinned = True
                    warnings.append(
                        f"WARNING: Unpinned dependency on line {line_num}: {line}"
                    )
                else:
                    print(
                        f"ERROR: Invalid requirement format on line {line_num}: {line}",
                        file=sys.stderr,
                    )
                    return False

            # Check for hash presence in the line
            if "--hash=" in line:
                has_hashes = True

    if has_unpinned:
        for w in warnings:
            print(w, file=sys.stderr)
        print(
            "ERROR: All dependencies must be pinned with == for reproducible builds.",
            file=sys.stderr,
        )
        print(
            "Use 'pip-compile --generate-hashes' to generate a locked requirements file.",
            file=sys.stderr,
        )
        return False

    if not has_hashes:
        print(
            "WARNING: No hash verification found in requirements file.",
            file=sys.stderr,
        )
        print(
            "RECOMMENDATION: Use 'pip-compile --generate-hashes' for supply chain security.",
            file=sys.stderr,
        )
        print(
            "Proceeding with --require-hashes enforcement if hashes are present...",
            file=sys.stderr,
        )

    return True


def get_pip_path() -> str:
    """Get the path to pip in the current Python environment."""
    # Use the pip associated with the current Python interpreter
    return sys.executable


def compute_file_hash(filepath: str) -> str:
    """Compute SHA256 hash of the requirements file for audit logging."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def install_requirements(
    requirements_file: str = "requirements.txt",
    use_hash_checking: bool = True,
) -> int:
    """
    Securely install Python requirements for CI/CD pipeline.

    Security design decisions:
    1. NO --upgrade flag: We use pinned versions for reproducibility.
       Using --upgrade defeats the purpose of pinned dependencies and
       introduces supply chain risk by pulling potentially compromised
       newer versions.
    2. Hash verification: --require-hashes ensures packages match expected
       hashes, preventing tampering.
    3. No custom index URLs: Only PyPI is used.
    4. No shell=True: Prevents shell injection.
    5. Validated input: Requirements file path is validated.

    Args:
        requirements_file: Path to requirements.txt (must be in project dir)
        use_hash_checking: Whether to enforce hash checking (default True)

    Returns:
        Exit code (0 for success)
    """
    print("=" * 60)
    print("Secure CI/CD Dependency Installation")
    print("=" * 60)

    # Step 1: Validate requirements file path
    if not validate_requirements_file(requirements_file):
        return 1

    resolved_path = str(Path(requirements_file).resolve())

    # Step 2: Compute and log file hash for audit trail
    file_hash = compute_file_hash(resolved_path)
    print(f"Requirements file: {resolved_path}")
    print(f"Requirements file SHA256: {file_hash}")

    # Step 3: Validate requirements file content
    if not validate_requirements_content(resolved_path):
        return 1

    # Step 4: Build pip command securely
    # NOTE: We intentionally do NOT use:
    #   --upgrade: Pinned versions should not be overridden
    #   --no-verify: Hash verification is critical for supply chain security
    #   --trusted-host: Only HTTPS to PyPI
    cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "--require-hashes",  # Enforce hash verification for supply chain security
        "--no-deps",  # Don't install unpinned transitive dependencies
        "--only-binary=:all:",  # Prefer binary wheels (avoid arbitrary code execution in setup.py)
        "-r",
        resolved_path,
    ]

    if not use_hash_checking:
        # Even when hash checking is disabled, we still pin versions
        # Remove --require-hashes but keep everything else
        cmd = [
            sys.executable,
            "-m",
            "pip",
            "install",
            "--no-deps",
            "--only-binary=:all:",
            "-r",
            resolved_path,
        ]
        print(
            "WARNING: Hash checking disabled. Supply chain security is reduced.",
            file=sys.stderr,
        )

    # Step 5: Log the command (without any secrets)
    print(f"Running: {' '.join(cmd)}")
    print("-" * 60)

    # Step 6: Execute pip install with no shell injection risk
    try:
        result = subprocess.run(
            cmd,
            check=False,  # We handle the return code ourselves
            shell=False,  # SECURITY: Never use shell=True
            capture_output=False,  # Let output flow to CI/CD logs
            timeout=600,  # 10 minute timeout to prevent hanging builds
            env=_get_sanitized_env(),
        )
        return result.returncode
    except subprocess.TimeoutExpired:
        print("ERROR: pip install timed out after 600 seconds", file=sys.stderr)
        return 1
    except FileNotFoundError:
        print(f"ERROR: Python executable not found: {sys.executable}", file=sys.stderr)
        return 1
    except Exception as e:
        print(f"ERROR: Unexpected error during installation: {e}", file=sys.stderr)
        return 1


def _get_sanitized_env() -> dict:
    """
    Create a sanitized environment for the subprocess.
    Removes potentially dangerous environment variables while keeping
    necessary ones for pip to function.
    """
    env = os.environ.copy()

    # Remove variables that could redirect pip to malicious sources
    dangerous_vars = [
        "PIP_INDEX_URL",
        "PIP_EXTRA_INDEX_URL",
        "PIP_FIND_LINKS",
        "PIP_TRUSTED_HOST",
        "PIP_NO_VERIFY",
        "PIP_CERT",
        "PIP_CLIENT_CERT",
        "PIP_CONFIG_FILE",  # Prevent loading malicious pip config
    ]

    for var in dangerous_vars:
        if var in env:
            print(
                f"WARNING: Removing potentially dangerous env var: {var}",
                file=sys.stderr,
            )
            del env[var]

    return env


def install_with_lockfile(
    lockfile: str = "requirements.txt",
    allow_no_hashes: bool = False,
) -> int:
    """
    Main entry point for CI/CD pipeline dependency installation.

    This function is designed to be called from CI/CD scripts.
    It enforces security best practices:
    - Pinned versions only (==)
    - Hash verification (--require-hashes)
    - No custom package indexes
    - No --upgrade flag (reproducible builds)

    To generate a proper lockfile with hashes:
        pip install pip-tools
        pip-compile --generate-hashes requirements.in -o requirements.txt

    Args:
        lockfile: Path to the locked requirements file
        allow_no_hashes: Set to True only if hashes are not yet available
                        (not recommended for production)

    Returns:
        Exit code (0 for success)
    """
    return install_requirements(
        requirements_file=lockfile,
        use_hash_checking=not allow_no_hashes,
    )


